import { logContext } from '../utils/context.js';

/**
 * Middleware that wraps the request in an AsyncLocalStorage 'run' block.
 * This allows all code inside the request lifecycle to access the same context.
 */
function contextMiddleware(req, res, next) {
    // Initialize context with the requestId generated by the requestIdMiddleware
    const context = { 
        requestId: req.id,
        method: req.method,
        url: req.originalUrl 
    };

    logContext.run(context, () => next());
}

export default contextMiddleware;
